+<!DOCTYPE html>
+<html lang="en">
+<head>
+    <meta charset="UTF-8">
+    <meta name="viewport" content="width=device-width, initial-scale=1.0">
+    <title>Stockyard Dashboard - Design Decisions</title>
+    <style>
+        :root {
+            --bg: #f8f9fa;
+            --card-bg: #ffffff;
+            --border: #e1e4e8;
+            --text: #24292e;
+            --text-muted: #586069;
+            --primary: #0366d6;
+            --primary-hover: #0256b9;
+            --success: #28a745;
+            --danger: #dc3545;
+            --warning: #ffc107;
+        }
+
+        * {
+            box-sizing: border-box;
+            margin: 0;
+            padding: 0;
+        }
+
+        body {
+            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
+            background: var(--bg);
+            color: var(--text);
+            line-height: 1.6;
+        }
+
+        .container {
+            max-width: 1200px;
+            margin: 0 auto;
+            padding: 2rem;
+        }
+
+        header {
+            text-align: center;
+            margin-bottom: 3rem;
+        }
+
+        header h1 {
+            font-size: 2rem;
+            margin-bottom: 0.5rem;
+        }
+
+        header p {
+            color: var(--text-muted);
+        }
+
+        .progress-bar {
+            display: flex;
+            justify-content: center;
+            gap: 0.5rem;
+            margin-bottom: 2rem;
+        }
+
+        .progress-step {
+            width: 12px;
+            height: 12px;
+            border-radius: 50%;
+            background: var(--border);
+            cursor: pointer;
+            transition: all 0.2s;
+        }
+
+        .progress-step.active {
+            background: var(--primary);
+            transform: scale(1.2);
+        }
+
+        .progress-step.completed {
+            background: var(--success);
+        }
+
+        .section {
+            display: none;
+            animation: fadeIn 0.3s ease;
+        }
+
+        .section.active {
+            display: block;
+        }
+
+        @keyframes fadeIn {
+            from { opacity: 0; transform: translateY(10px); }
+            to { opacity: 1; transform: translateY(0); }
+        }
+
+        .question {
+            background: var(--card-bg);
+            border: 1px solid var(--border);
+            border-radius: 8px;
+            padding: 2rem;
+            margin-bottom: 2rem;
+        }
+
+        .question h2 {
+            font-size: 1.25rem;
+            margin-bottom: 0.5rem;
+        }
+
+        .question p {
+            color: var(--text-muted);
+            margin-bottom: 1.5rem;
+        }
+
+        .options {
+            display: grid;
+            gap: 1rem;
+        }
+
+        .options.grid-2 {
+            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
+        }
+
+        .option {
+            border: 2px solid var(--border);
+            border-radius: 8px;
+            padding: 1rem;
+            cursor: pointer;
+            transition: all 0.2s;
+            position: relative;
+        }
+
+        .option:hover {
+            border-color: var(--primary);
+            background: #f6f8fa;
+        }
+
+        .option.selected {
+            border-color: var(--primary);
+            background: #f0f7ff;
+        }
+
+        .option.selected::after {
+            content: '✓';
+            position: absolute;
+            top: 0.5rem;
+            right: 0.5rem;
+            background: var(--primary);
+            color: white;
+            width: 24px;
+            height: 24px;
+            border-radius: 50%;
+            display: flex;
+            align-items: center;
+            justify-content: center;
+            font-size: 14px;
+        }
+
+        .option h3 {
+            font-size: 1rem;
+            margin-bottom: 0.5rem;
+        }
+
+        .option p {
+            font-size: 0.875rem;
+            color: var(--text-muted);
+            margin-bottom: 0;
+        }
+
+        /* Wireframe styles */
+        .wireframe {
+            background: #fafbfc;
+            border: 1px solid var(--border);
+            border-radius: 4px;
+            padding: 1rem;
+            margin-top: 1rem;
+            font-family: monospace;
+            font-size: 11px;
+        }
+
+        .wireframe-row {
+            display: flex;
+            gap: 0.5rem;
+            margin-bottom: 0.5rem;
+        }
+
+        .wireframe-box {
+            background: #e1e4e8;
+            border-radius: 3px;
+            padding: 0.5rem;
+            text-align: center;
+            flex: 1;
+        }
+
+        .wireframe-box.sidebar {
+            flex: 0 0 120px;
+            min-height: 150px;
+        }
+
+        .wireframe-box.main {
+            min-height: 150px;
+        }
+
+        .wireframe-box.header {
+            height: 40px;
+            display: flex;
+            align-items: center;
+            justify-content: center;
+        }
+
+        .wireframe-box.tall {
+            min-height: 200px;
+        }
+
+        .wireframe-box.small {
+            height: 60px;
+        }
+
+        .wireframe-box.metric {
+            height: 80px;
+        }
+
+        .wireframe-label {
+            color: var(--text-muted);
+            font-size: 10px;
+        }
+
+        .notes-section {
+            margin-top: 1.5rem;
+            padding-top: 1.5rem;
+            border-top: 1px solid var(--border);
+        }
+
+        .notes-section label {
+            display: block;
+            font-weight: 500;
+            margin-bottom: 0.5rem;
+            color: var(--text-muted);
+        }
+
+        .notes-section textarea {
+            width: 100%;
+            height: 80px;
+            padding: 0.75rem;
+            border: 1px solid var(--border);
+            border-radius: 6px;
+            font-family: inherit;
+            font-size: 0.875rem;
+            resize: vertical;
+        }
+
+        .notes-section textarea:focus {
+            outline: none;
+            border-color: var(--primary);
+        }
+
+        .nav-buttons {
+            display: flex;
+            justify-content: space-between;
+            margin-top: 2rem;
+        }
+
+        button {
+            background: var(--primary);
+            color: white;
+            border: none;
+            padding: 0.75rem 1.5rem;
+            border-radius: 6px;
+            font-size: 1rem;
+            cursor: pointer;
+            transition: background 0.2s;
+        }
+
+        button:hover {
+            background: var(--primary-hover);
+        }
+
+        button:disabled {
+            background: var(--border);
+            cursor: not-allowed;
+        }
+
+        button.secondary {
+            background: transparent;
+            color: var(--text);
+            border: 1px solid var(--border);
+        }
+
+        button.secondary:hover {
+            background: #f6f8fa;
+        }
+
+        /* Summary section */
+        .summary {
+            background: var(--card-bg);
+            border: 1px solid var(--border);
+            border-radius: 8px;
+            padding: 2rem;
+        }
+
+        .summary h2 {
+            margin-bottom: 1rem;
+        }
+
+        .summary-item {
+            padding: 1rem 0;
+            border-bottom: 1px solid var(--border);
+        }
+
+        .summary-item:last-child {
+            border-bottom: none;
+        }
+
+        .summary-item strong {
+            display: block;
+            margin-bottom: 0.25rem;
+        }
+
+        .summary-item span {
+            color: var(--primary);
+        }
+
+        .copy-section {
+            margin-top: 2rem;
+            padding-top: 2rem;
+            border-top: 2px solid var(--border);
+        }
+
+        .copy-section h3 {
+            margin-bottom: 1rem;
+        }
+
+        textarea {
+            width: 100%;
+            height: 300px;
+            font-family: monospace;
+            font-size: 13px;
+            padding: 1rem;
+            border: 1px solid var(--border);
+            border-radius: 6px;
+            resize: vertical;
+        }
+
+        .copy-button {
+            margin-top: 1rem;
+        }
+
+        /* Visual mockups */
+        .mockup {
+            background: #1a1a2e;
+            border-radius: 8px;
+            padding: 1rem;
+            margin-top: 1rem;
+            color: #a0a0b0;
+            font-family: monospace;
+            font-size: 11px;
+            overflow: hidden;
+        }
+
+        .mockup-header {
+            display: flex;
+            gap: 0.5rem;
+            padding-bottom: 0.75rem;
+            border-bottom: 1px solid #2a2a3e;
+            margin-bottom: 0.75rem;
+        }
+
+        .mockup-dot {
+            width: 10px;
+            height: 10px;
+            border-radius: 50%;
+        }
+
+        .mockup-dot.red { background: #ff5f56; }
+        .mockup-dot.yellow { background: #ffbd2e; }
+        .mockup-dot.green { background: #27ca40; }
+
+        .mockup-content {
+            display: flex;
+            gap: 1rem;
+        }
+
+        .mockup-sidebar {
+            width: 140px;
+            flex-shrink: 0;
+        }
+
+        .mockup-nav-item {
+            padding: 0.5rem;
+            border-radius: 4px;
+            margin-bottom: 0.25rem;
+        }
+
+        .mockup-nav-item.active {
+            background: #2a2a3e;
+            color: #fff;
+        }
+
+        .mockup-main {
+            flex: 1;
+        }
+
+        .mockup-card {
+            background: #2a2a3e;
+            border-radius: 6px;
+            padding: 0.75rem;
+            margin-bottom: 0.5rem;
+        }
+
+        .mockup-card-title {
+            color: #fff;
+            margin-bottom: 0.5rem;
+        }
+
+        .mockup-grid {
+            display: grid;
+            grid-template-columns: repeat(3, 1fr);
+            gap: 0.5rem;
+        }
+
+        .mockup-metric {
+            background: #2a2a3e;
+            border-radius: 4px;
+            padding: 0.5rem;
+            text-align: center;
+        }
+
+        .mockup-metric-value {
+            color: #4ade80;
+            font-size: 1.25rem;
+            font-weight: bold;
+        }
+
+        .mockup-table {
+            width: 100%;
+            margin-top: 0.5rem;
+        }
+
+        .mockup-table-row {
+            display: flex;
+            padding: 0.5rem 0;
+            border-bottom: 1px solid #2a2a3e;
+        }
+
+        .mockup-table-row:last-child {
+            border-bottom: none;
+        }
+
+        .mockup-table-cell {
+            flex: 1;
+        }
+
+        .mockup-status {
+            display: inline-block;
+            padding: 0.125rem 0.5rem;
+            border-radius: 3px;
+            font-size: 10px;
+        }
+
+        .mockup-status.running { background: #166534; color: #4ade80; }
+        .mockup-status.stopped { background: #1e3a5f; color: #60a5fa; }
+        .mockup-status.failed { background: #7f1d1d; color: #f87171; }
+
+        .mockup-tabs {
+            display: flex;
+            gap: 1rem;
+            border-bottom: 1px solid #2a2a3e;
+            margin-bottom: 0.75rem;
+            padding-bottom: 0.5rem;
+        }
+
+        .mockup-tab {
+            padding: 0.25rem 0;
+        }
+
+        .mockup-tab.active {
+            color: #fff;
+            border-bottom: 2px solid #4ade80;
+        }
+
+        .mockup-chart {
+            height: 60px;
+            background: linear-gradient(to right, #166534 0%, #166534 60%, #ca8a04 60%, #ca8a04 80%, #dc2626 80%);
+            border-radius: 4px;
+            opacity: 0.6;
+            position: relative;
+        }
+
+        .mockup-chart::after {
+            content: '▁▂▃▄▅▆▇█▇▆▅▆▇█▇▆▅▄▃▄▅▆▇';
+            position: absolute;
+            bottom: 0;
+            left: 0;
+            right: 0;
+            text-align: center;
+            letter-spacing: -2px;
+            color: #4ade80;
+            opacity: 0.7;
+        }
+
+        .mockup-log {
+            font-size: 10px;
+            height: 80px;
+            overflow: hidden;
+            background: #0d0d1a;
+            padding: 0.5rem;
+            border-radius: 4px;
+        }
+
+        .mockup-log-line {
+            display: flex;
+            gap: 0.5rem;
+        }
+
+        .mockup-log-time {
+            color: #666;
+        }
+
+        .mockup-log-text {
+            color: #a0a0b0;
+        }
+
+        .recommendation {
+            background: #fff8e6;
+            border-left: 3px solid var(--warning);
+            padding: 0.75rem 1rem;
+            margin-top: 1rem;
+            font-size: 0.875rem;
+        }
+
+        .recommendation strong {
+            color: #856404;
+        }
+    </style>
+</head>
+<body>
+    <div class="container">
+        <header>
+            <h1>Stockyard Dashboard Design</h1>
+            <p>Click through each decision to build your dashboard specification</p>
+        </header>
+
+        <div class="progress-bar" id="progressBar"></div>
+
+        <!-- Section 1: Navigation Structure -->
+        <div class="section active" data-section="0">
+            <div class="question">
+                <h2>1. Navigation Structure</h2>
+                <p>How should the dashboard be organized at the top level?</p>
+
+                <div class="options grid-2">
+                    <div class="option" data-question="nav_structure" data-value="sidebar">
+                        <h3>Sidebar Navigation</h3>
+                        <p>Persistent left sidebar with main sections. Common in data-heavy dashboards.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div class="mockup-content">
+                                <div class="mockup-sidebar">
+                                    <div class="mockup-nav-item active">Fleet</div>
+                                    <div class="mockup-nav-item">VMs</div>
+                                    <div class="mockup-nav-item">Repos</div>
+                                    <div class="mockup-nav-item">Activity</div>
+                                    <div class="mockup-nav-item">Settings</div>
+                                </div>
+                                <div class="mockup-main">
+                                    <div class="mockup-card">
+                                        <div class="mockup-card-title">Fleet Overview</div>
+                                        <div style="color:#666">Main content area...</div>
+                                    </div>
+                                </div>
+                            </div>
+                        </div>
+                    </div>
+
+                    <div class="option" data-question="nav_structure" data-value="topnav">
+                        <h3>Top Navigation</h3>
+                        <p>Horizontal nav bar at top. Maximizes vertical content space.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div class="mockup-tabs" style="border-bottom: 1px solid #2a2a3e; padding: 0.5rem 0;">
+                                <div class="mockup-tab active">Fleet</div>
+                                <div class="mockup-tab">VMs</div>
+                                <div class="mockup-tab">Repos</div>
+                                <div class="mockup-tab">Activity</div>
+                                <div class="mockup-tab" style="margin-left: auto;">Settings</div>
+                            </div>
+                            <div class="mockup-card" style="min-height: 120px;">
+                                <div class="mockup-card-title">Fleet Overview</div>
+                                <div style="color:#666">Main content area with more vertical space...</div>
+                            </div>
+                        </div>
+                    </div>
+
+                    <div class="option" data-question="nav_structure" data-value="hybrid">
+                        <h3>Hybrid (Recommended)</h3>
+                        <p>Minimal top bar for global actions, context-specific tabs within pages.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div style="display: flex; justify-content: space-between; padding: 0.5rem; border-bottom: 1px solid #2a2a3e; margin-bottom: 0.5rem;">
+                                <div style="color:#fff; font-weight: bold;">Stockyard</div>
+                                <div style="display: flex; gap: 1rem;">
+                                    <span>Fleet</span>
+                                    <span>Activity</span>
+                                    <span style="color:#4ade80;">●</span>
+                                </div>
+                            </div>
+                            <div class="mockup-tabs">
+                                <div class="mockup-tab active">Overview</div>
+                                <div class="mockup-tab">By Repo</div>
+                                <div class="mockup-tab">By Owner</div>
+                            </div>
+                            <div class="mockup-card">
+                                <div style="color:#666">Content with contextual sub-navigation...</div>
+                            </div>
+                        </div>
+                        <div class="recommendation">
+                            <strong>Recommended:</strong> Scales better as features grow. Top bar stays simple, complexity moves to contextual tabs.
+                        </div>
+                    </div>
+                </div>
+            </div>
+
+            <div class="notes-section">
+                <label>Additional notes for this decision:</label>
+                <textarea data-notes="nav_structure" placeholder="Any thoughts, constraints, or alternatives to consider..."></textarea>
+            </div>
+
+            <div class="nav-buttons">
+                <button class="secondary" disabled>Previous</button>
+                <button onclick="nextSection()">Next</button>
+            </div>
+        </div>
+
+        <!-- Section 2: Fleet Overview Layout -->
+        <div class="section" data-section="1">
+            <div class="question">
+                <h2>2. Fleet Overview Layout</h2>
+                <p>How should the main dashboard display fleet status?</p>
+
+                <div class="options">
+                    <div class="option" data-question="fleet_layout" data-value="metrics_top">
+                        <h3>Metrics Bar + Table</h3>
+                        <p>Summary metrics at top, detailed VM list below. Classic dashboard pattern.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div class="mockup-grid" style="margin-bottom: 1rem;">
+                                <div class="mockup-metric">
+                                    <div class="mockup-metric-value">24</div>
+                                    <div>Running</div>
+                                </div>
+                                <div class="mockup-metric">
+                                    <div class="mockup-metric-value" style="color:#60a5fa;">8</div>
+                                    <div>Stopped</div>
+                                </div>
+                                <div class="mockup-metric">
+                                    <div class="mockup-metric-value" style="color:#f87171;">2</div>
+                                    <div>Failed</div>
+                                </div>
+                            </div>
+                            <div class="mockup-table">
+                                <div class="mockup-table-row" style="color:#fff; font-weight:bold;">
+                                    <div class="mockup-table-cell">VM</div>
+                                    <div class="mockup-table-cell">Repo</div>
+                                    <div class="mockup-table-cell">Owner</div>
+                                    <div class="mockup-table-cell">CPU</div>
+                                    <div class="mockup-table-cell">Status</div>
+                                </div>
+                                <div class="mockup-table-row">
+                                    <div class="mockup-table-cell">vm-abc123</div>
+                                    <div class="mockup-table-cell">stockyard</div>
+                                    <div class="mockup-table-cell">jesse</div>
+                                    <div class="mockup-table-cell">45%</div>
+                                    <div class="mockup-table-cell"><span class="mockup-status running">running</span></div>
+                                </div>
+                                <div class="mockup-table-row">
+                                    <div class="mockup-table-cell">vm-def456</div>
+                                    <div class="mockup-table-cell">claude-code</div>
+                                    <div class="mockup-table-cell">bot</div>
+                                    <div class="mockup-table-cell">92%</div>
+                                    <div class="mockup-table-cell"><span class="mockup-status running">running</span></div>
+                                </div>
+                            </div>
+                        </div>
+                    </div>
+
+                    <div class="option" data-question="fleet_layout" data-value="grouped_cards">
+                        <h3>Grouped Cards (Recommended)</h3>
+                        <p>VMs grouped by repository in collapsible cards. Matches your priority of repo grouping.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div class="mockup-card">
+                                <div style="display: flex; justify-content: space-between; margin-bottom: 0.5rem;">
+                                    <div class="mockup-card-title">stockyard <span style="color:#666; font-weight:normal;">3 VMs</span></div>
+                                    <div><span style="color:#4ade80;">●</span> 2 running <span style="color:#60a5fa;">●</span> 1 stopped</div>
+                                </div>
+                                <div class="mockup-table">
+                                    <div class="mockup-table-row">
+                                        <div class="mockup-table-cell">vm-abc123</div>
+                                        <div class="mockup-table-cell">jesse</div>
+                                        <div class="mockup-table-cell">CPU 45% | Mem 2.1GB</div>
+                                        <div class="mockup-table-cell"><span class="mockup-status running">running</span></div>
+                                    </div>
+                                    <div class="mockup-table-row">
+                                        <div class="mockup-table-cell">vm-xyz789</div>
+                                        <div class="mockup-table-cell">bot</div>
+                                        <div class="mockup-table-cell">CPU 12% | Mem 1.8GB</div>
+                                        <div class="mockup-table-cell"><span class="mockup-status running">running</span></div>
+                                    </div>
+                                </div>
+                            </div>
+                            <div class="mockup-card">
+                                <div style="display: flex; justify-content: space-between; margin-bottom: 0.5rem;">
+                                    <div class="mockup-card-title">claude-code <span style="color:#666; font-weight:normal;">5 VMs</span></div>
+                                    <div><span style="color:#4ade80;">●</span> 4 running <span style="color:#f87171;">●</span> 1 failed</div>
+                                </div>
+                                <div style="color:#666; font-size: 10px;">Click to expand...</div>
+                            </div>
+                        </div>
+                        <div class="recommendation">
+                            <strong>Recommended:</strong> Aligns with your priority of repo grouping. Natural hierarchy for finding VMs.
+                        </div>
+                    </div>
+
