+
+                    <div class="option" data-question="ssh_access" data-value="protocol_handler">
+                        <h3>SSH Protocol Handler</h3>
+                        <p>Click opens ssh:// link, launches system terminal. Seamless but requires setup.</p>
+                        <div class="mockup">
+                            <div class="mockup-header">
+                                <div class="mockup-dot red"></div>
+                                <div class="mockup-dot yellow"></div>
+                                <div class="mockup-dot green"></div>
+                            </div>
+                            <div style="padding: 0.5rem;">
+                                <div style="color:#fff; margin-bottom: 0.5rem;">vm-abc123</div>
+                                <div>
+                                    <span style="background:#4ade80; color:#000; padding: 0.25rem 0.75rem; border-radius: 4px; font-size: 11px;">🔗 Open SSH</span>
+                                </div>
+                                <div style="color:#666; font-size: 10px; margin-top: 0.5rem;">Opens your default terminal</div>
+                            </div>
+                        </div>
+                    </div>
+                </div>
+            </div>
+
+            <div class="notes-section">
+                <label>Additional notes for this decision:</label>
+                <textarea data-notes="ssh_access" placeholder="Any thoughts, constraints, or alternatives to consider..."></textarea>
+            </div>
+
+            <div class="nav-buttons">
+                <button class="secondary" onclick="prevSection()">Previous</button>
+                <button onclick="nextSection()">Next</button>
+            </div>
+        </div>
+
+        <!-- Section 10: Summary -->
+        <div class="section" data-section="9">
+            <div class="summary">
+                <h2>Your Dashboard Design Decisions</h2>
+                <p>Review your selections below. You can go back to change any decision.</p>
+
+                <div id="summaryContent"></div>
+
+                <div class="copy-section">
+                    <h3>Copy for Claude</h3>
+                    <p style="color: var(--text-muted); margin-bottom: 1rem;">Copy this text and paste it back to continue the design process:</p>
+                    <textarea id="exportText" readonly></textarea>
+                    <button class="copy-button" onclick="copyExport()">Copy to Clipboard</button>
+                    <div id="copyConfirm" style="color: var(--success); margin-top: 0.5rem; display: none;">✓ Copied to clipboard!</div>
+                </div>
+            </div>
+
+            <div class="nav-buttons">
+                <button class="secondary" onclick="prevSection()">Previous</button>
+                <button disabled>Complete</button>
+            </div>
+        </div>
+    </div>
+
+    <script>
+        const decisions = {};
+        const notes = {};
+        const questions = {
+            nav_structure: {
+                title: "Navigation Structure",
+                options: {
+                    sidebar: "Sidebar Navigation",
+                    topnav: "Top Navigation",
+                    hybrid: "Hybrid (top bar + contextual tabs)"
+                }
+            },
+            fleet_layout: {
+                title: "Fleet Overview Layout",
+                options: {
+                    metrics_top: "Metrics Bar + Table",
+                    grouped_cards: "Grouped Cards (by repo)",
+                    split_view: "Split View (list + preview)"
+                }
+            },
+            vm_detail_layout: {
+                title: "VM Detail View Layout",
+                options: {
+                    tabbed: "Tabbed Sections",
+                    stacked: "Stacked Panels (single page)",
+                    columns: "Column Layout (metrics | logs)"
+                }
+            },
+            metrics_display: {
+                title: "Resource Metrics Visualization",
+                options: {
+                    sparklines: "Sparklines (inline mini-charts)",
+                    gauges: "Gauge/Progress Bars",
+                    timeseries: "Time Series Charts",
+                    hybrid_metrics: "Hybrid (sparklines + expandable)"
+                }
+            },
+            log_display: {
+                title: "Log Viewing Experience",
+                options: {
+                    streaming: "Live Streaming (tail -f style)",
+                    paginated: "Paginated/Historical",
+                    both_logs: "Both (toggle mode)",
+                    split_logs: "Split (stdout + stderr)"
+                }
+            },
+            activity_feed: {
+                title: "Activity Feed",
+                options: {
+                    timeline: "Timeline Feed (chronological)",
+                    notifications: "Notification Center (dropdown)",
+                    dashboard_widget: "Dashboard Widget",
+                    separate_page: "Separate Activity Page"
+                }
+            },
+            vm_actions: {
+                title: "VM Actions & Controls",
+                options: {
+                    inline_buttons: "Inline Buttons (always visible)",
+                    hover_reveal: "Hover Reveal",
+                    dropdown_menu: "Dropdown Menu (three-dot)",
+                    detail_page_only: "Detail Page Only"
+                }
+            },
+            alert_display: {
+                title: "Problem/Alert Indicators",
+                options: {
+                    inline_warning: "Inline Warning Style (row color)",
+                    problems_section: "Problems Section (top of page)",
+                    badge_count: "Badge + Filter",
+                    sort_to_top: "Auto-Sort to Top"
+                }
+            },
+            ssh_access: {
+                title: "SSH Access (V1)",
+                options: {
+                    copy_button: "Copy Command Button",
+                    quick_copy: "Quick Copy Icon",
+                    modal_details: "Connection Modal",
+                    protocol_handler: "SSH Protocol Handler"
+                }
+            }
+        };
+
+        let currentSection = 0;
+        const totalSections = 10;
+
+        function initProgressBar() {
+            const bar = document.getElementById('progressBar');
+            for (let i = 0; i < totalSections; i++) {
+                const step = document.createElement('div');
+                step.className = 'progress-step' + (i === 0 ? ' active' : '');
+                step.onclick = () => goToSection(i);
+                bar.appendChild(step);
+            }
+        }
+
+        function updateProgressBar() {
+            const steps = document.querySelectorAll('.progress-step');
+            steps.forEach((step, i) => {
+                step.classList.remove('active');
+                if (i < currentSection) {
+                    step.classList.add('completed');
+                } else if (i === currentSection) {
+                    step.classList.add('active');
+                }
+            });
+        }
+
+        function goToSection(index) {
+            if (index < 0 || index >= totalSections) return;
+
+            document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
+            document.querySelector(`[data-section="${index}"]`).classList.add('active');
+            currentSection = index;
+            updateProgressBar();
+
+            if (index === totalSections - 1) {
+                updateSummary();
+            }
+        }
+
+        function nextSection() {
+            goToSection(currentSection + 1);
+        }
+
+        function prevSection() {
+            goToSection(currentSection - 1);
+        }
+
+        function selectOption(element) {
+            const question = element.dataset.question;
+            const value = element.dataset.value;
+
+            // Deselect siblings
+            element.parentElement.querySelectorAll('.option').forEach(opt => {
+                opt.classList.remove('selected');
+            });
+
+            // Select this one
+            element.classList.add('selected');
+            decisions[question] = value;
+        }
+
+        function updateSummary() {
+            collectNotes();
+            const content = document.getElementById('summaryContent');
+            let html = '';
+
+            for (const [key, value] of Object.entries(decisions)) {
+                const q = questions[key];
+                const noteText = notes[key] ? `<p style="color: var(--text-muted); font-size: 0.875rem; margin-top: 0.25rem;"><em>Note: ${notes[key]}</em></p>` : '';
+                html += `
+                    <div class="summary-item">
+                        <strong>${q.title}</strong>
+                        <span>${q.options[value]}</span>
+                        ${noteText}
+                    </div>
+                `;
+            }
+
+            if (Object.keys(decisions).length === 0) {
+                html = '<p style="color: var(--text-muted);">No decisions made yet. Go back and select options.</p>';
+            }
+
+            content.innerHTML = html;
+            updateExportText();
+        }
+
+        function collectNotes() {
+            document.querySelectorAll('textarea[data-notes]').forEach(textarea => {
+                const key = textarea.dataset.notes;
+                if (textarea.value.trim()) {
+                    notes[key] = textarea.value.trim();
+                } else {
+                    delete notes[key];
+                }
+            });
+        }
+
+        function updateExportText() {
+            collectNotes();
+
+            const lines = [
+                "# Stockyard Dashboard Design Decisions",
+                "",
+                "## Context (Already Confirmed)",
+                "- Users: Human operators (full view) + developers (own VMs). Agents use CLI/MCP.",
+                "- Auth: Tailscale identity",
+                "- Observability: Logs + status + resource metrics",
+                "- Fleet view priorities: Repo grouping, resource consumption, recent activity",
+                "- VM detail view: Status, logs, resource graphs (snapshots nice-to-have)",
+                "- Alerts: In-dashboard indicators for v1",
+                "- Web terminal: Design for it, implement later (copy-paste SSH for v1)",
+                "",
+                "## UI/UX Decisions from Prototype",
+                ""
+            ];
+
+            for (const [key, value] of Object.entries(decisions)) {
+                const q = questions[key];
+                lines.push(`**${q.title}:** ${q.options[value]}`);
+                if (notes[key]) {
+                    lines.push(`  - Notes: ${notes[key]}`);
+                }
+            }
+
+            if (Object.keys(decisions).length < Object.keys(questions).length) {
+                lines.push("");
+                lines.push("⚠️ Note: Not all decisions were made. Missing:");
+                for (const key of Object.keys(questions)) {
+                    if (!decisions[key]) {
+                        lines.push(`- ${questions[key].title}`);
+                    }
+                }
+            }
+
+            // Include any notes for decisions that weren't made
+            const notesWithoutDecisions = Object.keys(notes).filter(k => !decisions[k]);
+            if (notesWithoutDecisions.length > 0) {
+                lines.push("");
+                lines.push("## Additional Notes (no selection made)");
+                for (const key of notesWithoutDecisions) {
+                    lines.push(`**${questions[key].title}:** ${notes[key]}`);
+                }
+            }
+
+            lines.push("");
+            lines.push("---");
+            lines.push("Please proceed with the design document based on these decisions.");
+
+            document.getElementById('exportText').value = lines.join('\n');
+        }
+
+        function copyExport() {
+            const textarea = document.getElementById('exportText');
+            textarea.select();
+            document.execCommand('copy');
+
+            const confirm = document.getElementById('copyConfirm');
+            confirm.style.display = 'block';
+            setTimeout(() => {
+                confirm.style.display = 'none';
+            }, 2000);
+        }
+
+        // Initialize
+        document.addEventListener('DOMContentLoaded', () => {
+            initProgressBar();
+
+            // Add click handlers to all options
+            document.querySelectorAll('.option').forEach(opt => {
+                opt.addEventListener('click', () => selectOption(opt));
+            });
+        });
+    </script>
+</body>
+</html>
